-- seed_gymcoach_realistic.sql
-- Curated realistic seed data for a personalized gym/fitness system
-- Generated on 2026-04-08
-- Target: PostgreSQL / psql
--
-- Usage:
--   psql -U <user> -f seed_gymcoach_realistic.sql
--
-- Notes:
--   1) This script uses \connect to seed multiple databases when they exist.
--   2) If you only use one database, copy the matching section and run it separately.
--   3) IDs are prefixed with seed_ so they are easy to identify and clean up later.
--   4) Nutrition macros are realistic sample values intended for demos/testing, not a certified clinical database.

\set ON_ERROR_STOP on
SET client_encoding = 'UTF8';

\echo Seeding gymcoach (monolith)
\connect gymcoach
BEGIN;
ON CONFLICT (id) DO UPDATE SET
  "userId" = EXCLUDED."userId",
  age = EXCLUDED.age,
  gender = EXCLUDED.gender,
  "heightCm" = EXCLUDED."heightCm",
  goal = EXCLUDED.goal,
  "activityLevel" = EXCLUDED."activityLevel",
  "experienceLevel" = EXCLUDED."experienceLevel",
  "preferredTrainingDays" = EXCLUDED."preferredTrainingDays",
  "availableEquipment" = EXCLUDED."availableEquipment",
  injuries = EXCLUDED.injuries,
  "currentWeight" = EXCLUDED."currentWeight",
  "targetWeight" = EXCLUDED."targetWeight",
  "createdAt" = EXCLUDED."createdAt",
  "updatedAt" = EXCLUDED."updatedAt",
  "isPT" = EXCLUDED."isPT";
ON CONFLICT (id) DO UPDATE SET
  exercise_name = EXCLUDED.exercise_name,
  type_of_activity = EXCLUDED.type_of_activity,
  type_of_equipment = EXCLUDED.type_of_equipment,
  body_part = EXCLUDED.body_part,
  type = EXCLUDED.type,
  muscle_groups_activated = EXCLUDED.muscle_groups_activated,
  instructions = EXCLUDED.instructions,
  video_url = EXCLUDED.video_url,
  created_at = EXCLUDED.created_at,
  updated_at = EXCLUDED.updated_at;
ON CONFLICT (id) DO UPDATE SET
  user_id = EXCLUDED.user_id,
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  date = EXCLUDED.date,
  duration = EXCLUDED.duration,
  notes = EXCLUDED.notes,
  created_at = EXCLUDED.created_at,
  updated_at = EXCLUDED.updated_at;
ON CONFLICT (id) DO UPDATE SET
  workout_id = EXCLUDED.workout_id,
  exercise_id = EXCLUDED.exercise_id,
  sets = EXCLUDED.sets,
  reps = EXCLUDED.reps,
  duration = EXCLUDED.duration,
  weight = EXCLUDED.weight,
  notes = EXCLUDED.notes,
  "order" = EXCLUDED."order",
  created_at = EXCLUDED.created_at;
ON CONFLICT (id) DO UPDATE SET
  user_id = EXCLUDED.user_id,
  date = EXCLUDED.date,
  meal_type = EXCLUDED.meal_type,
  food_name = EXCLUDED.food_name,
  calories = EXCLUDED.calories,
  protein = EXCLUDED.protein,
  carbs = EXCLUDED.carbs,
  fats = EXCLUDED.fats,
  notes = EXCLUDED.notes,
  created_at = EXCLUDED.created_at,
  updated_at = EXCLUDED.updated_at;
ON CONFLICT (id) DO UPDATE SET
  user_id = EXCLUDED.user_id,
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  goal = EXCLUDED.goal,
  duration = EXCLUDED.duration,
  days_per_week = EXCLUDED.days_per_week,
  plan = EXCLUDED.plan,
  created_at = EXCLUDED.created_at,
  updated_at = EXCLUDED.updated_at;
ON CONFLICT (id) DO UPDATE SET
  user_id = EXCLUDED.user_id,
  question = EXCLUDED.question,
  answer = EXCLUDED.answer,
  model_used = EXCLUDED.model_used,
  response_time = EXCLUDED.response_time,
  relevance = EXCLUDED.relevance,
  relevance_explanation = EXCLUDED.relevance_explanation,
  prompt_tokens = EXCLUDED.prompt_tokens,
  completion_tokens = EXCLUDED.completion_tokens,
  total_tokens = EXCLUDED.total_tokens,
  cost = EXCLUDED.cost,
  feedback = EXCLUDED.feedback,
  feedback_timestamp = EXCLUDED.feedback_timestamp,
  created_at = EXCLUDED.created_at;
COMMIT;

